import{_ as t,o,c as d,ae as a}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Facebook Ads Overview","description":"","frontmatter":{"title":"Facebook Ads Overview","slug":"facebook-ads-overview"},"headers":[],"relativePath":"marketer-hub/facebook-ads-overview.md","filePath":"marketer-hub/facebook-ads-overview.md"}'),c={name:"marketer-hub/facebook-ads-overview.md"};function r(i,e,n,s,l,_){return o(),d("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch Links can be used together with <a href="http://facebook.com/" target="_blank" rel="noreferrer">Facebook</a> ads, allowing you to track ad-driven installs on the Branch Dashboard and deep link those new users directly to the content the first time they open your app. Refer to <a href="https://www.facebook.com/business/ads-guide" target="_blank" rel="noreferrer">Facebook&#39;s Ad Guide</a> to learn more.</p><p>Facebook&#39;s Ad Platform supports numerous campaign types and a shared set of advertisement formats. This guide will help you navigate Facebook&#39;s Advertisement Platform and show you how to use Branch Links in all major Facebook ad types.</p><h2 id="campaign-support" tabindex="-1">Campaign support <a class="header-anchor" href="#campaign-support" aria-label="Permalink to &quot;Campaign support&quot;">​</a></h2><p>This documentation supports the following Facebook Ad Campaigns:</p><table tabindex="0"><thead><tr><th>Facebook campaign category</th><th>Campaign type/objective</th><th>Link users to</th><th>Branch documentation link</th><th>Branch ad format</th></tr></thead><tbody><tr><td>Awareness</td><td>Brand Awareness</td><td>Web</td><td><a href="./facebook-platform-ads.html#brand-awareness-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr><tr><td>Awareness</td><td>Reach</td><td>Web</td><td><a href="./facebook-platform-ads.html#reach-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr><tr><td>Consideration</td><td>Traffic</td><td>Web or App</td><td><a href="./facebook-traffic-and-conversion-ads.html#traffic-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr><tr><td>Consideration</td><td>App Installs</td><td>App</td><td><a href="./facebook-app-install-ads.html"><strong>link</strong></a></td><td>App Only: Installs</td></tr><tr><td>Consideration</td><td>Video Views</td><td>Web</td><td><a href="./facebook-platform-ads.html#video-views-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr><tr><td>Consideration</td><td>Lead Generation</td><td>Web x</td><td><a href="./facebook-platform-ads.html#lead-generation-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr><tr><td>Conversion</td><td>Conversions</td><td>Web or App</td><td><a href="./facebook-traffic-and-conversion-ads.html#conversions-campaign-setup"><strong>link</strong></a></td><td>Cross-platform Display</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>If you have <strong>more than one app</strong> using the same Facebook Account ID, SKAdNetwork data may only appear in one of those apps. Do not connect the same Facebook Account ID in multiple apps to avoid visualization issues.</p></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Facebook has confirmed that impression tracking links are <strong>not supported in any ad placement</strong>, and click tracking links are only available in a <strong>subset of placements.</strong></p></div><h2 id="data-mapping-between-branch-and-facebook" tabindex="-1">Data mapping between Branch and Facebook <a class="header-anchor" href="#data-mapping-between-branch-and-facebook" aria-label="Permalink to &quot;Data mapping between Branch and Facebook&quot;">​</a></h2><h3 id="event-names" tabindex="-1">Event names <a class="header-anchor" href="#event-names" aria-label="Permalink to &quot;Event names&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Note</p><p>Please follow the <a href="./track-branch-events.html">Tracking Commerce, Content, Lifecycle and Custom Events</a> guide when implementing event tracking in the Branch SDK.<br> When tracking any of the Facebook events that are mapped to the Branch <code>custom</code> event, use the event name from the table below; e.g. <code>branch.logevent(&#39;AdClick&#39;)</code>.</p></div><table tabindex="0"><thead><tr><th><strong>Facebook event name</strong></th><th><strong>Branch event name</strong></th></tr></thead><tbody><tr><td><code>AdClick</code></td><td><code>Custom</code></td></tr><tr><td><code>AdImpression</code></td><td><code>Custom</code></td></tr><tr><td><code>Contact</code></td><td><code>Custom</code></td></tr><tr><td><code>CustomizeProduct</code></td><td><code>Custom</code></td></tr><tr><td><code>Donate</code></td><td><code>Custom</code></td></tr><tr><td><code>fb_mobile_achievement_unlocked</code></td><td><code>UNLOCK_ACHIEVEMENT</code></td></tr><tr><td><code>MOBILE_APP_INSTALL</code></td><td><code>INSTALL</code></td></tr><tr><td><code>fb_mobile_activate_app</code></td><td><code>OPEN</code></td></tr><tr><td><code>fb_mobile_add_payment_info</code></td><td><code>ADD_PAYMENT_INFO</code></td></tr><tr><td><code>fb_mobile_add_to_cart</code></td><td><code>ADD_TO_CART</code></td></tr><tr><td><code>fb_mobile_add_to_wishlist</code></td><td><code>ADD_TO_WISHLIST</code></td></tr><tr><td><code>fb_mobile_complete_registration</code></td><td><code>COMPLETE_REGISTRATION</code></td></tr><tr><td><code>fb_mobile_content_view</code></td><td><code>VIEW_ITEM</code></td></tr><tr><td><code>fb_mobile_initiated_checkout</code></td><td><code>INITIATE_PURCHASE</code></td></tr><tr><td><code>fb_mobile_level_achieved</code></td><td><code>ACHIEVE_LEVEL</code></td></tr><tr><td><code>fb_mobile_purchase</code></td><td><code>PURCHASE</code></td></tr><tr><td><code>fb_mobile_rate</code></td><td><code>RATE</code></td></tr><tr><td><code>fb_mobile_search</code></td><td><code>SEARCH</code></td></tr><tr><td><code>fb_mobile_spent_credits</code></td><td><code>SPEND_CREDITS</code></td></tr><tr><td><code>fb_mobile_tutorial_completion</code></td><td><code>COMPLETE_TUTORIAL</code></td></tr><tr><td><code>FindLocation</code></td><td><code>Custom</code></td></tr><tr><td><code>Schedule</code></td><td><code>Custom</code></td></tr><tr><td><code>StartTrial</code></td><td><code>START_TRIAL</code></td></tr><tr><td><code>SubmitApplication</code></td><td><code>Custom</code></td></tr><tr><td><code>Subscribe</code></td><td><code>Custom</code></td></tr></tbody></table><h3 id="campaign-and-ad-data" tabindex="-1">Campaign and Ad Data <a class="header-anchor" href="#campaign-and-ad-data" aria-label="Permalink to &quot;Campaign and Ad Data&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>Branch data</strong></th><th><strong>Facebook data</strong></th></tr></thead><tbody><tr><td><code>last_attributed_touch_data_tilde_ad_set_name</code></td><td><code>campaign_name</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_ad_set_id</code></td><td><code>campaign_id</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_secondary_publisher</code></td><td><code>publisher_platform</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_creative_name</code></td><td><code>creative_name</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_creative_id</code></td><td><code>creative_id</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_ad_name</code></td><td><code>adgroup_name</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_ad_id</code></td><td><code>adgroup_id</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_campaign</code></td><td><code>campaign_group_name</code></td></tr><tr><td><code>last_attributed_touch_data_tilde_campaign_id</code></td><td><code>campaign_group_id</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>The <code>creative_id</code> and <code>creative_name</code> fields are automatically set server-side on Facebook for Cost, Clicks, and Impressions sent to Branch.</p></div><h3 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>Branch key-value pair</strong></th><th><strong>Facebook MMP key-value pair</strong></th><th><strong>Facebook event(s) supported</strong></th></tr></thead><tbody><tr><td><code>event_data.revenue</code></td><td><code>_valueToSum</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>event_data.currency</code></td><td><code>fb_currency</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items(array).$quantity</code></td><td><code>fb_num_items</code></td><td><code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code></td></tr><tr><td><code>content_items (array)</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_tutorial_completion</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$sku</code></td><td><code>fb_content_id</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_tutorial_completion</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$product_category</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$product_brand</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$product_name</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$price</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$og_title</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$keywords</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>content_items[i].$custom_fields</code></td><td><code>fb_content (array)</code></td><td><code>fb_mobile_add_to_cart</code>, <code>fb_mobile_add_to_wishlist</code>, <code>fb_mobile_initiated_checkout</code>, <code>fb_mobile_purchase</code>, <code>fb_mobile_rate</code>, <code>fb_mobile_search</code>, <code>fb_mobile_spent_credits</code>, <code>fb_mobile_content_view</code></td></tr><tr><td><code>event_data.search_query</code></td><td><code>fb_search_string</code></td><td><code>fb_mobile_search</code></td></tr><tr><td><code>custom_data.fb_payment_info_available</code></td><td><code>fb_payment_info_available</code></td><td><code>fb_mobile_initiated_checkout</code></td></tr><tr><td><code>custom_data.level</code></td><td><code>fb_level</code></td><td><code>fb_mobile_level_achieved</code></td></tr><tr><td><code>custom_data.fb_success</code></td><td><code>fb_success</code></td><td><code>fb_mobile_add_payment_info</code>, <code>fb_mobile_tutorial_completion</code>, <code>fb_mobile_search</code></td></tr><tr><td><code>custom_data.fb_registration_method</code></td><td><code>fb_registration_method</code></td><td><code>fb_mobile_complete_registration</code></td></tr></tbody></table><p>Branch will send all content items tracked for an event, if supported.</p><p>Also, Branch will automatically map <code>&quot;fb_content_type&quot;:&quot;product&quot;</code> for in-app events when the advertiser <a href="./create-branch-objects-and-events.html#buo-content-metadata-properties">tracks</a> <code>ContentMetadata</code> via a Branch SDK. Otherwise, Branch will not add the <code>fb_content_type</code> variable.</p><h2 id="viewing-facebook-data" tabindex="-1">Viewing Facebook data <a class="header-anchor" href="#viewing-facebook-data" aria-label="Permalink to &quot;Viewing Facebook data&quot;">​</a></h2><p>You can see analytics on impressions, clicks, installs, opens and conversion events on various pages of the <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you&#39;re seeing discrepancies between Facebook and Branch data, please see <a href="./common-sources-of-san-reporting-discrepancies.html">Common Sources of SAN Reporting Discrepancies</a>.</p></div><h3 id="data-limitations" tabindex="-1">Data limitations <a class="header-anchor" href="#data-limitations" aria-label="Permalink to &quot;Data limitations&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Note</p><ul><li><p>Branch may redact specific metrics/events (ex. INSTALLS) through the Branch Dashboard or through Aggregate Exports of Facebook-attributed campaigns when aggregation levels are not high enough to prevent the potential de-anonymization of specific Facebook users or if it is non-aggregated view-through and click-through data.</p><ul><li>In these cases, the Branch Dashboard will display &quot;undisclosed&quot; in reports and Aggregate Exports will show <code>null</code> in responses.</li></ul></li><li><p>Only for Android events, you can get the event detail but not &quot;undisclosed&quot; with <a href="./facebook-install-referrer.html">Facebook Install Referrer</a>.</p></li><li><p>We cannot send device-level Facebook attribution data to third parties, unless attribution results utilized the <a href="./facebook-install-referrer.html">Facebook Install Referrer</a> or <a href="./enable-app-aggregated-event-measurement-support.html">Aggregate Event Measurement</a>.</p></li><li><p>This data is also not returned in the deep link session initialization callback within the app. If you have analytics needs that are not met by the Branch Dashboard, please <a href="./submit-a-ticket.html">contact us</a> and include &quot;Facebook MMP + Feature Request&quot; in the subject.</p></li><li><p>Branch will purge last-attributed data after 60 days.</p></li></ul></div><table tabindex="0"><thead><tr><th><strong>Branch feature</strong></th><th><strong>Facebook data included</strong></th></tr></thead><tbody><tr><td><a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Dashboard visualizations</a></td><td>Pre-aggregated analytics</td></tr><tr><td><a href="./query-api.html">Query API</a></td><td>Pre-aggregated analytics</td></tr><tr><td><a href="https://dashboard.branch.io/liveview" target="_blank" rel="noreferrer">Liveview</a></td><td>Pre-aggregated analytics</td></tr><tr><td><a href="./daily-exports-api.html">Daily Export API</a></td><td>Not supported</td></tr><tr><td><a href="https://branch.dashboard.branch.io/data-import-export/csv-exports" target="_blank" rel="noreferrer">CSV Exports</a></td><td>Pre-aggregated analytics</td></tr><tr><td><a href="./webhooks.html">Webhooks</a></td><td>Pre-aggregated analytics</td></tr><tr><td><a href="./data-integration-partners.html">Data Integrations</a></td><td>Not supported</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Looking for <strong>Advanced Mobile Measurement</strong>? Visit our dedicated <a href="./meta-advanced-mobile-measurement.html">guide</a>.</p></div><h3 id="facebook-limited-data-use" tabindex="-1">Facebook Limited Data Use <a class="header-anchor" href="#facebook-limited-data-use" aria-label="Permalink to &quot;Facebook Limited Data Use&quot;">​</a></h3><p>On July 1st 2020, Facebook introduced a new <a href="https://www.facebook.com/business/help/1151133471911882" target="_blank" rel="noreferrer">Limited Data Use (LDU)</a> feature to support customer compliance with the California Consumer Privacy Act (CCPA). This feature enables you to limit how Facebook uses the data of users in states where Limited Data Use is available. This data could be collected by you or by third parties on your behalf.</p><p>If the Limited Data Use feature is enabled, Facebook will process data in accordance with its role as a service provider or processor with respect to flagged personal information from people in states where Limited Data Use is available. This means Facebook will limit use of that data subject to their <a href="https://www.facebook.com/legal/terms/state-specific" target="_blank" rel="noreferrer">State-Specific Terms</a>.</p><p>To invoke Meta Limited Data Use for your users, please use any <a href="https://help.branch.io/developers-hub/docs/honoring-opt-out-of-processing-requests#configure-sdk-privacy-controls" target="_blank" rel="noreferrer">Consumer Protection Preference</a> other than <a href="https://help.branch.io/developers-hub/docs/honoring-opt-out-of-processing-requests#using-sdk-privacy-controls" target="_blank" rel="noreferrer">FULL</a>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>We also have a document with <a href="./facebook-faq-and-advanced-options.html">FAQs and Advanced Options</a> for Facebook Ads. We recommend starting with one of the guides above, then jumping into the FAQ and Advanced Options when you have questions or need to troubleshoot.</p>',32)])])}const m=t(c,[["render",r]]);export{h as __pageData,m as default};
